import{_ as e,c as a,o as l,a6 as t}from"./chunks/framework.Dk6vZ2f8.js";const i="/images/v2-dev/pc_1_micro_app.png",s="/images/v2-dev/pc_2_v1_style.png",o="/images/v2-dev/docker.png",c="/images/v2-dev/add_widget.png",r="/images/v2-dev/m2.jpg",n="/images/v2-dev/m1.jpg",f=JSON.parse('{"title":"Sun-Panel V2 开发版已发布","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"v2/zh_cn/index.md","filePath":"v2/zh_cn/index.md","lastUpdated":1772706260000}'),d={name:"v2/zh_cn/index.md"},h=t('<h1 id="sun-panel-v2-开发版已发布" tabindex="-1">Sun-Panel V2 开发版已发布 <a class="header-anchor" href="#sun-panel-v2-开发版已发布" aria-label="Permalink to &quot;Sun-Panel V2 开发版已发布&quot;">​</a></h1><h2 id="bug反馈-功能建议-测试交流群" tabindex="-1">BUG反馈/功能建议/测试交流群 <a class="header-anchor" href="#bug反馈-功能建议-测试交流群" aria-label="Permalink to &quot;BUG反馈/功能建议/测试交流群&quot;">​</a></h2><ul><li>V2-QQ群：924455282 （或任意Sun-Panel群<code>@作者</code>都可以，倾听各种建议）</li><li>反馈地址：<a href="https://txc.qq.com/products/798902" target="_blank" rel="noreferrer">https://txc.qq.com/products/798902</a></li><li>github Issues：<a href="https://github.com/hslr-s/sun-panel/issues" target="_blank" rel="noreferrer">https://github.com/hslr-s/sun-panel/issues</a></li><li>微应用开发者，添加作者微信（95302870），备注：<code>微应用</code>，作者拉开发者群，更好的沟通</li></ul><h2 id="关于开发版必读说明" tabindex="-1">关于开发版必读说明 <a class="header-anchor" href="#关于开发版必读说明" aria-label="Permalink to &quot;关于开发版必读说明&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">❗️❗️❗️❗️❗️ 必读！必读！必读！❗️❗️❗️❗️❗️</p><ul><li>开发板 <strong>底部有开发版说明</strong> 请勿直接应用在公开的正式环境中。</li><li>v2目前正在开发测试阶段，可能会出现一些不可控的BUG，如果追求稳定的小伙伴，<strong>对 AI 、 docker 和 NAS 相关是刚入门的小伙伴</strong>，<strong>不推荐尝试体验v2开发版本</strong>。</li><li>V2 开发版本已经支持V1以升级的方式<strong>覆盖更新</strong>，但是功能还在测试中，❗️⚠️<strong>请勿按此操作</strong>⚠️❗️，请使用 v1 导出备份包在另外部署 v2 中恢复体验。</li><li>测试版本（Beta版本）发布后，开发版本将仅支持离线使用，不能登录 Sun-Panel PRO 账号，所以请不要应用在正式环境中。</li><li>少部分v1的功能在前几个版本还没来得及适配，后续会逐渐适配，可参考下面功能列表。</li></ul></div><h3 id="开发版本福利" tabindex="-1">开发版本福利 <a class="header-anchor" href="#开发版本福利" aria-label="Permalink to &quot;开发版本福利&quot;">​</a></h3><p>为了更快的发布v2正式版本，所以希望邀请更多小伙伴加入体验新版功能，特此部分<strong>开发</strong>版本（暂不含v2测试版本），仅在开发版本登录上 <a href="https://pro.sun-panel.top" target="_blank" rel="noreferrer">Sun-Panel 服务平台</a> 的账号，即可免费使用 PRO 功能，使用高级功能。</p><p>开发版本（DEV）测试期间，参与测试的小伙伴如果能提出有效的BUG（首次提出），待正式版发布后，会公示名单，根据有效数量可以打折（8折/5折）购买永久PRO授权。</p><h3 id="邀请各位开发者大佬和ai开发大佬开发微应用和小部件" tabindex="-1">邀请各位开发者大佬和AI开发大佬开发微应用和小部件 <a class="header-anchor" href="#邀请各位开发者大佬和ai开发大佬开发微应用和小部件" aria-label="Permalink to &quot;邀请各位开发者大佬和AI开发大佬开发微应用和小部件&quot;">​</a></h3><p>参阅文档 <a href="/v2/zh_cn/micro_app_dev/index.html">微应用开发</a>，文档在不断完善。添加作者微信（95302870），备注：<code>微应用</code>，作者拉开发者群，更好的沟通</p><h2 id="v2-功能" tabindex="-1">V2 功能 <a class="header-anchor" href="#v2-功能" aria-label="Permalink to &quot;V2 功能&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>以下列出相比v1现已完成的功能项，图标卡片在保留v1版本样式的同时，同组支持更多尺寸的卡片，当然远不止这些，简单挑了一些，有新的建议可以提！</p></div><ul class="contains-task-list"><li>✅ 增加 微应用/小部件卡片框架，在有限的屏幕里，提升无限的可玩性，灵活安装和卸载。喜爱开发的小伙伴可以按照规范自由开发。</li><li>✅ 全新的网络环境检测方案，可根据当前访问页面地址，匹配到合适的内网地址、自定义地址内的同网段地址。</li><li>✅ 增加 卡片自定义地址，可以参与网络环境识别智能打开或右键菜单打开。</li><li>✅ 重构 导航页面， <ul><li>跨分组拖拽卡片</li><li>增加不同尺寸混用（目前支持【比例（行x列）】<code>1x1</code>,<code>1x2</code>,<code>2x1</code>,<code>2x2</code>,<code>2x4</code>,<code>1x屏宽</code>），微应用开发者可参照此配置开发不同尺寸的小部件。</li><li>手机端完美适配小部件以及其他尺寸卡片</li><li>精简卡片dom</li></ul></li><li>✅ docker 管理器 从原列表改为卡片风格，显示效果更好</li><li>✅ 全新docker卡片，2x2卡片支持显示容器的实时网速和累计流量。</li><li>✅ 图标卡片支持备注文本，仅登录可见。</li><li>✅ 二进制文件，增加 Mac 端（arm64,amd64）二进制文件运行，取消了cgo的sqlite库支持，采用全go sqlite库（所有端二进制未完全测试，有测试的小伙伴给个反馈结果，感谢）</li><li>✅ 导入v1图标配置数据</li><li>✅ 备份功能适配</li><li>✅ 图库批量删除功能</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 对接三方自托管图标库</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 内置功能（docker，系统监控等）小部件</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 侧栏目录</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> v1版本的系统状态组件适配</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 更多三方适配微应用/小部件</li><li class="task-list-item"><input class="task-list-item-checkbox" disabled="" type="checkbox"> 更多请期待...</li></ul><h2 id="安装方式" tabindex="-1">安装方式 <a class="header-anchor" href="#安装方式" aria-label="Permalink to &quot;安装方式&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>与 <a href="/zh_cn/usage/quick_deploy.html">v1安装方式</a> 一致。<strong>此为开发版本，目前与v1版本数据不兼容，请勿覆盖更新和应用在正式环境内</strong></p></div><ul><li>开发版本拉取命令 <code>docker pull hslr/sun-panel:2.0.0-dev-9</code> 此处文档更新可能不及时，docker 标签名可在v2测试群里公告看到。或参考docker官网：<a href="https://hub.docker.com/r/hslr/sun-panel/tags" target="_blank" rel="noreferrer">https://hub.docker.com/r/hslr/sun-panel/tags</a></li><li>二进制文件下载地址：<a href="https://pan.quark.cn/s/68492917cc31" target="_blank" rel="noreferrer">夸克盘</a></li></ul><h2 id="微应用下载地址" tabindex="-1">微应用下载地址 <a class="header-anchor" href="#微应用下载地址" aria-label="Permalink to &quot;微应用下载地址&quot;">​</a></h2><ul><li><a href="/v2/zh_cn/micro_app_store.html">前往</a></li></ul><h2 id="v2-效果预览图" tabindex="-1">V2 效果预览图 <a class="header-anchor" href="#v2-效果预览图" aria-label="Permalink to &quot;V2 效果预览图&quot;">​</a></h2><p><img src="'+i+'" alt=""></p><p><img src="'+s+'" alt=""></p><p><img src="'+o+'" alt=""></p><p><img src="'+c+'" alt=""></p><p><img src="'+r+'" alt="" style="max-width:500px;"></p><p><img src="'+n+'" alt="" style="max-width:500px;"></p>',25),p=[h];function u(m,_,k,b,g,v){return l(),a("div",null,p)}const q=e(d,[["render",u]]);export{f as __pageData,q as default};
